select kml.* ,case when lb.count is null then 0 else lb.count end as count from kb_category_label kcl left join kb_model_label kml on kcl.l_id = kml.id left join (select l_id, count(1) as count from kb_basic_label group by l_id) lb on lb.l_id = kml.id
